  "title": "ग्लोबल सेकेंडरी इंडेक्स",
  "group": "डायनामोडीबी इंडेक्स",
  "options": [
    {
      "text": "प्राथमिक कुंजी के समान"
    },
    {
      "text": "अतिरिक्त लागत से मुक्त"
    },
    {
      "text": "लेखन प्रदर्शन को घटाता है"
    },
    {
      "text": "गैर‑प्राथमिक गुणों पर क्वेरी करने की अनुमति देता है"
    }
  ],
  "questionProse": [
    "डायनामोडीबी में ग्लोबल सेकेंडरी इंडेक्स का उद्देश्य क्या है?"
  ],
  "explanationProse": [
    "ग्लोबल सेकेंडरी इंडेक्स (GSI):\n    - गैर‑प्राथमिक कुंजी गुणों पर क्वेरी करने की अनुमति देता है\n    - वैकल्पिक एक्सेस पैटर्न बनाता है\n    - क्वेरी लचीलापन बढ़ाता है\n    - अतिरिक्त लिखने की क्षमता की लागत के साथ आता है\n\n    प्राथमिक कुंजी से परे जटिल क्वेरी आवश्यकताओं के लिए उपयोगी है।\n\n    [डायनामोडीबी इंडेक्स](https://docs.aws.amazon.com/amazondynamodb/latest/developerguide/GSI.html)"
  ]
}
